// JSON Builder & Validator
class JSONOptimizer {
  // Construire JSON optimal pour l'IA
  buildOptimalStructure(data, purpose) {
    const structure = {
      metadata: {
        version: "1.0",
        purpose: purpose,
        timestamp: new Date().toISOString(),
        schema: this.generateSchema(data)
      },
      data: this.normalizeData(data),
      validation: {
        isValid: true,
        errors: [],
        warnings: []
      }
    };

    return structure;
  }

  // GГ©nГ©rer schГ©ma automatiquement
  generateSchema(data) {
    const schema = {
      type: typeof data === 'object' ? 
        (Array.isArray(data) ? 'array' : 'object') : 
        typeof data,
      properties: {}
    };

    if (schema.type === 'object') {
      for (let [key, value] of Object.entries(data)) {
        schema.properties[key] = {
          type: this.getType(value),
          required: value !== null && value !== undefined,
          example: this.sanitizeExample(value)
        };
      }
    }

    return schema;
  }

  // Validation stricte
  validateJSON(json, schema) {
    const errors = [];
    const warnings = [];

    // Check required fields
    for (let field of schema.required || []) {
      if (!(field in json)) {
        errors.push(`Missing required field: ${field}`);
      }
    }

    // Check types
    for (let [key, value] of Object.entries(json)) {
      if (schema.properties && schema.properties[key]) {
        const expectedType = schema.properties[key].type;
        const actualType = this.getType(value);

        if (expectedType !== actualType) {
          warnings.push(`Type mismatch: ${key} expected ${expectedType}, got ${actualType}`);
        }
      }
    }

    // Check nesting depth
    const depth = this.getMaxDepth(json);
    if (depth > 5) {
      warnings.push(`Deep nesting detected: ${depth} levels`);
    }

    return {
      valid: errors.length === 0,
      errors,
      warnings,
      score: 1 - (errors.length * 0.2 + warnings.length * 0.1)
    };
  }
}

